var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>챔버 도시관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>チェンバー都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is an announcement from Chamber City Management.</color>","TWN":"<color=#ffd34c>密室城市管理局通知。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 도심 전역에서 침식체가 출몰하고 있습니다.</color>","JPN":"<color=#ffd34c>現在、都市全域にて侵食体が出現中。</color>","ENG":"<color=#ffd34c>Currently, C.O.s are appearing across the entire city.</color>","TWN":"<color=#ffd34c>目前，整個市中心皆有侵蝕體出沒。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최고 등급 재난 경보가 발령되었으니, 도시에 계신 시민 여러분은 신속하게 대피하시길 바랍니다.</color>","JPN":"<color=#ffd34c>最高ランクの災難警報が発令されました。市民の皆さんは迅速に避難してください。</color>","ENG":"<color=#ffd34c>The highest-level disaster alert has been issued. All citizens in the city are to evacuate immediately.</color>","TWN":"<color=#ffd34c>已發布最高等級災難警報，請位於城市的各位市民盡快撤離。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아아아악–!!","JPN":"きゃあああー！！","ENG":"Kyaaaah–!!","TWN":"呃啊啊啊啊–！！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"헬프 미! SOS! 이머전시, 메이데이, 이대로 죽고 싶지 않아아아–––!!","JPN":"ヘルプミー！ SOS！　エマージェンシー、メーデー、このまま死にたくないぃぃぃ───！！","ENG":"Help me! SOS! Emergency, mayday! I don't wanna die like this–––!!","TWN":"救命！SOS！緊急，Mayday，我不想就這樣死掉–––！！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"괜찮으신가요?","JPN":"大丈夫ですか？","ENG":"Are you all right?","TWN":"妳還好嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"허억… 이게… 괜찮아 보이는… 허억…….","JPN":"はあっ……これが……大丈夫そうに見え……はあっ……","ENG":"*Huff...* D-does... this look– *Huff...*","TWN":"呼呃…那個…我看起來好嗎…呼呃……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저, 주제넘지만…….","JPN":"あの、大変恐縮ですが……","ENG":"I know it's presumptuous, but...","TWN":"雖、雖然很冒昧……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"비스트 타입 침식체는 정면보다 하복부가 약한 편이니, 파고드는 편이 좋다고 생각해요.","JPN":"ビーストタイプの侵食体は正面より下腹部が弱いので、もうちょっと踏み込むほうがいいと思います。","ENG":"Beast-type C.O.s are weaker in the lower abdomen than head-on. You should dive in low.","TWN":"但野獸類型侵蝕體的下腹比正面還弱，我認為鑽進去會比較好。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민서. 여긴 미쳤어요. 당장 빠져나가야 한다고요…!!","JPN":"ヒミコさん、ここはダメです。今すぐ逃げないと……！！","ENG":"Minseo, this place is insane. We need to get out, now...!!","TWN":"旼序，這裡瘋了，我們要馬上脫離…！！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"응? 민서, 어디 있어요?","JPN":"うん？　ヒミコさん、どこですか？","ENG":"Huh? Minseo, where are you?","TWN":"嗯？旼序，妳在哪裡？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아아아악–!! 민서 양––––!!!!","JPN":"きゃああああー！！　ヒミコさぁぁぁん────！！！","ENG":"Kyaaaah–!! Minseo––––!!!!","TWN":"呃啊啊啊啊–！！旼序小姐––––！！！！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"나는 벌레… 침식체님의 먹이…….","JPN":"ヒミコは虫……侵食体さんの餌……","ENG":"I'm a bug... fodder for the C.O.s...","TWN":"我是蟲子…侵蝕體的糧食……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"사지뼈의 정령님, 부디 안 아프게 부서져주세요…….","JPN":"四肢の精霊さん、どうか痛くないように砕けてください……","ENG":"O spirits of my limb bones, please break me without pain...","TWN":"四肢骨的精靈，請讓我無痛粉碎……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"워, 워. 하늘 덮은 먹구름 떼에 도망치는 건 내 하드보일드함이랑은 맞지 않지.","JPN":"やれやれ。空を覆う暗雲から逃げるなんて、私のハードボイルドさには似合わないな。","ENG":"Whoa there. Fleeing beneath a sky of black clouds isn't my hard-boiled style.","TWN":"哦、哦，逃到覆蓋天空的烏雲堆裡，不符合我的冷酷無情。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"적장의 목을 베었으니 술잔 가득 봄 햇살을 비추시게, 친구.","JPN":"敵将の首は切り落とした。盃いっぱい春の日差しを照らそうじゃないか、友よ。","ENG":"I've taken the enemy leader's head, friend. So let our cups brim with spring sunlight.","TWN":"既然砍下了敵將的頭，就讓酒杯映照滿滿的春光吧，朋友。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"1종짜리 하나 잡아놓고 뭘 꺼드럭대는 건가요…….","JPN":"第1種を1体倒しただけで何格好つけてるんですか……","ENG":"You felled a measly Category 1 and you're grandstanding...","TWN":"抓了一個1類有什麼好自以為是的……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그나마 덜 무섭게 죽을 기회였는데, 이젠 가망이 없어요…….","JPN":"さっき怖くない死に方ができるチャンスだったのに、もう無理です……","ENG":"That was my chance to die less painfully. Now we're doomed...","TWN":"本來是個至少不會死得這麼可怕的機會，現在沒希望了……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"중장님. 3중대가 고위 관료분들의 대피를 무사히 끝마쳤다고 합니다.","JPN":"中将。第3中隊が高位官僚たちを無事避難させたとのことです。","ENG":"Lieutenant General, 3rd Company reports the senior officials have been evacuated safely.","TWN":"中將，3中隊已經順利完成高層官員的撤離工作。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 거리의 침식체도 순탄하게 정리되어 가고 있는 듯해.","JPN":"ああ、街の侵食体も順調に片付いている。","ENG":"Good. The C.O.s on the street are being cleared smoothly, too.","TWN":"好，街上的侵蝕體整頓工作似乎也進行得很順利。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만… 이상하군.","JPN":"だが……妙だな。","ENG":"But... something's odd.","TWN":"但是…真奇怪。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"예? 그게 무슨 말씀이십니까?","JPN":"はい？　どういうことですか？","ENG":"Ma'am? What do you mean?","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이번 일은 북방합의체가 관리국과 합중국에 협력을 요청했네.","JPN":"今回の件は、北方合意体から管理局と合衆国に協力を求めてきた件だ。","ENG":"The Northern Union asked the Administration and the States for cooperation this time.","TWN":"這次的事北方和議會向管理局跟合眾國請求合作。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 경보 발령 후 수 시간이 지났음에도… 우리 쪽에 지나칠 정도로 피해가 적군.","JPN":"だが、警報発令から数時間が経ったにもかかわらず……我々の被害が異常に少ない。","ENG":"Yet hours after the alert... casualties on our side are suspiciously low.","TWN":"但即使警報發布後過了好幾個小時…我們這邊受到的損害還是非常小。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"하지만 중장님. 이전 최고 등급 재난 역시 침식체에 대한 피해는 적었습니다.","JPN":"ですが中将。以前起きた最高ランクの災難でも、侵食体による被害の規模は大きくありませんでした。","ENG":"But ma'am, during the last highest-level disaster, damage from C.O.s was low as well.","TWN":"不過中將，以前最高等級災難對侵蝕體造成的損害也很小。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"챔버의 대균열은 지하에 있기까지 하니, 지상 쪽 피해는 적지 않겠습니까?","JPN":"それにチェンバーの大亀裂は地下にある分、地上の被害は少なくて当然ではないでしょうか？","ENG":"Chamber's Grand Dimension Crevice is underground, so surface damage should be limited, right?","TWN":"密室的大峽谷在地下，所以地面的損害應該不小吧？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대균열 확장은 부차적인 문제일 뿐. 우리가 대비한 건 세계를 멸망시킬 재난 현상일세.","JPN":"大亀裂の拡張はあくまで付随的な問題にすぎない。我々が備えているのは、世界を滅ぼす災難現象だ。","ENG":"The Grand Dimension Crevice expansion is secondary. We prepared for a calamity that could end the world.","TWN":"大峽谷擴張只是次要問題，我們要應對的是讓世界滅亡的災難現象。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 그 현상이 확정적으로 일어날 미래였다는 걸 생각하면, 어쩌면…….","JPN":"そしてその現象が確定的に起こる未来だということを考えると、もしかしたら……","ENG":"And considering that future was supposedly certain, maybe...","TWN":"而且想到那個現象是未來確定會發生的事，也許……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이건 군용 기밀 회선? 갑자기 무슨 일이지?","JPN":"これは……軍用機密回線？　急に何事だ？","ENG":"A military secure line? What's this about?","TWN":"這是軍用機密線路？突然是怎麼回事？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"바, 방어선의 공병부대로부터 보고입니다!","JPN":"ぼ、防衛線の工兵部隊から報告します！","ENG":"R-report from engineers on the defense line!","TWN":"防、防線工兵部隊報告！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"CSE레벨 급상승…! 현재 도심 일부 지역에 3등급 침식지대가–.","JPN":"CSEレベルが急上昇……！　現在、都心の一部地域にレベル3の侵食地帯が……","ENG":"CSE levels are spiking...! Parts of the city have now become a level 3 Corrupted Area–","TWN":"CSE等級急遽上升…！目前市中心部分地區3級侵蝕地帶–"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};